class IndexedFile:
 def __init__(self):
 self.index = {}
 self.data = []

 def add_record(self, key, value):
 self.index[key] = len(self.data)
 self.data.append(value)

 def get_record(self, key):
 position = self.index.get(key, -1)
 if position != -1:
 return self.data[position]
 return None

# Usage
if __name__ == '__main__':
 fs = IndexedFile()
 fs.add_record(1001, 'Student A')
 fs.add_record(1002, 'Student B')
 print(fs.get_record(1002))
